func (ns *Namespace) ReadFile(i any) (string, error) {
	s, err := cast.ToStringE(i)
	if err != nil {
		return "", err
	}

	if ns.deps.PathSpec != nil {
		s = ns.deps.PathSpec.RelPathify(s)
	}

	s, err = readFile(ns.readFileFs, s)
	if err != nil && herrors.IsNotExist(err) {
		return "", nil
	}
	return s, err
}
